import { eq, asc, sql, and, inArray } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { tasks, modules, milestones } from '$lib/db/schema.js';
import type { TaskStatus } from '$lib/db/schema.js';
import type {
	ClaimTaskInput,
	ProgressTaskInput,
	CompleteTaskInput,
	AdminTaskActionInput,
	UpdateTaskInput,
	BlockTaskInput,
	UnblockTaskInput
} from '$lib/schemas/index.js';
import { isValidTransition } from '$lib/schemas/index.js';

// ── ID Generation ────────────────────────────────────────────────────────────

/** Get next TASK-{global_seq} ID and short_id. */
export async function nextTaskId(db: BetterSQLite3Database<any>): Promise<{ id: string; shortId: number }> {
	const rows = await db.select({ id: tasks.id, shortId: tasks.shortId }).from(tasks).all();
	let maxSeq = 0;
	let maxShort = 0;
	for (const row of rows) {
		const seq = parseInt(row.id.replace('TASK-', ''), 10);
		if (seq > maxSeq) maxSeq = seq;
		if (row.shortId > maxShort) maxShort = row.shortId;
	}
	return { id: `TASK-${maxSeq + 1}`, shortId: maxShort + 1 };
}

// ── List (with filters) ─────────────────────────────────────────────────────

export interface TaskFilters {
	status?: string;
	milestoneId?: string;
	moduleId?: string;
}

export async function listTasks(
	db: BetterSQLite3Database<any>,
	filters: TaskFilters = {}
) {
	const conditions = [];
	if (filters.status) conditions.push(eq(tasks.status, filters.status as TaskStatus));
	if (filters.moduleId) conditions.push(eq(tasks.moduleId, filters.moduleId));

	// If milestoneId, join through modules
	if (filters.milestoneId) {
		const modRows = await db
			.select({ id: modules.id })
			.from(modules)
			.where(eq(modules.milestoneId, filters.milestoneId))
			.all();
		const modIds = modRows.map((m) => m.id);
		if (modIds.length === 0) return [];
		conditions.push(inArray(tasks.moduleId, modIds));
	}

	const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
	const rows = await db
		.select()
		.from(tasks)
		.where(whereClause)
		.orderBy(asc(tasks.shortId))
		.all();
	return rows.map(formatTaskResponse);
}

// ── Get Detail ───────────────────────────────────────────────────────────────

export async function getTask(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const row = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!row) return null;

	// Resolve module and milestone info
	const mod = await db.select().from(modules).where(eq(modules.id, row.moduleId)).get();
	const milestone = mod
		? await db.select().from(milestones).where(eq(milestones.id, mod.milestoneId)).get()
		: null;

	return {
		...formatTaskResponse(row),
		module: mod
			? {
					id: mod.id,
					milestoneId: mod.milestoneId,
					name: mod.name,
					status: mod.status
				}
			: null,
		milestone: milestone
			? {
					id: milestone.id,
					title: milestone.title,
					status: milestone.status
				}
			: null
	};
}

// ── Claim (optimistic lock) ──────────────────────────────────────────────────

export async function claimTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ClaimTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Only allow claiming if task is todo or in-progress
	if (existing.status !== 'todo' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	// Optimistic lock: if already assigned to someone else, reject
	if (existing.assignee && existing.assignee !== data.assignee) {
		return {
			error: 'conflict' as const,
			currentAssignee: existing.assignee,
			task: formatTaskResponse(existing)
		};
	}

	// Transition status if needed
	const statusUpdate =
		existing.status === 'todo' ? 'in-progress' : undefined;

	const updates: Record<string, any> = { assignee: data.assignee };
	if (statusUpdate) updates.status = statusUpdate;
	updates.updatedAt = sql`(unixepoch())`;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Progress ─────────────────────────────────────────────────────────────────

export async function progressTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ProgressTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	if (existing.status !== 'in-progress' && existing.status !== 'todo' && existing.status !== 'blocked') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = { updatedAt: sql`(unixepoch())` };
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;
	if (data.subTotal !== undefined) updates.subTotal = data.subTotal;
	if (data.subDone !== undefined) updates.subDone = data.subDone;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Complete ─────────────────────────────────────────────────────────────────

export async function completeTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: CompleteTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Must be in review or in-progress to complete
	if (existing.status !== 'review' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = {
		status: 'done',
		updatedAt: sql`(unixepoch())`,
		reportedAt: sql`(unixepoch())`
	};
	if (data.commitHash !== undefined) updates.commitHash = data.commitHash ?? null;
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;
	if (data.evidence !== undefined) updates.evidenceJson = data.evidence.length > 0 ? JSON.stringify(data.evidence) : null;
	if (data.filesTouched !== undefined) updates.filesTouched = data.filesTouched.length > 0 ? JSON.stringify(data.filesTouched) : null;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Admin Action ─────────────────────────────────────────────────────────────

export type AdminActionError = {
	error: 'not_found' | 'invalid_transition' | 'invalid_status';
	detail?: string;
};

export async function adminTaskAction(
	db: BetterSQLite3Database<any>,
	id: string,
	data: AdminTaskActionInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Admin can force any status, but validate transition for non-force actions
	// For admin actions, we allow any status change (admin override)
	const updates: Record<string, any> = {
		status: data.status,
		updatedAt: sql`(unixepoch())`
	};

	// If setting to done, also set reportedAt
	if (data.status === 'done' && !existing.reportedAt) {
		updates.reportedAt = sql`(unixepoch())`;
	}
	// If reopening from done, clear reportedAt
	if (data.status !== 'done' && existing.reportedAt) {
		updates.reportedAt = null;
	}

	if (data.progressMessage !== undefined) {
		updates.progressMessage = data.progressMessage ?? null;
	}

	// Handle assignee clearing (force release) or assignment
	if (data.assignee !== undefined) {
		updates.assignee = data.assignee ?? null;
	}

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Update task (edit properties) ───────────────────────────────────────────

export async function updateTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	const updates: Record<string, any> = { updatedAt: sql`(unixepoch())` };
	if (data.title !== undefined) updates.title = data.title;
	if (data.description !== undefined) updates.description = data.description ?? null;
	if (data.assignee !== undefined) updates.assignee = data.assignee ?? null;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Block ────────────────────────────────────────────────────────────────────

export async function blockTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: BlockTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	if (existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = {
		status: 'blocked',
		blockedReason: data.reason,
		updatedAt: sql`(unixepoch())`
	};

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Unblock ──────────────────────────────────────────────────────────────────

export async function unblockTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UnblockTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	if (existing.status !== 'blocked') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = {
		status: 'in-progress',
		blockedReason: null,
		updatedAt: sql`(unixepoch())`
	};

	if (data.message !== undefined) {
		updates.progressMessage = data.message;
	}

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Kanban Data (with zombie detection) ─────────────────────────────────────

const ZOMBIE_THRESHOLD_MS = 24 * 60 * 60 * 1000; // 24 hours

export async function listKanbanData(db: BetterSQLite3Database<any>, milestoneId: string) {
	// Fetch milestone
	const milestone = await db.select().from(milestones).where(eq(milestones.id, milestoneId)).get();
	if (!milestone) return null;

	// Fetch modules
	const modRows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.orderBy(asc(modules.sortOrder))
		.all();

	const now = Date.now();

	// Fetch tasks per module with zombie flag
	const modulesWithTasks = await Promise.all(
		modRows.map(async (mod) => {
			const taskRows = await db
				.select()
				.from(tasks)
				.where(eq(tasks.moduleId, mod.id))
				.all();

			const tasksWithZombie = taskRows.map((row) => {
				const formatted = formatTaskResponse(row);
				const isZombie =
					row.status === 'in-progress' &&
					(now - new Date(row.updatedAt).getTime()) > ZOMBIE_THRESHOLD_MS;
				return { ...formatted, isZombie };
			});

			const totalTasks = tasksWithZombie.length;
			const doneTasks = tasksWithZombie.filter((t) => t.status === 'done').length;
			const progressPercent = totalTasks > 0 ? Math.round((doneTasks / totalTasks) * 100) : 0;

			// Collect unique assignees
			const assignees = [...new Set(tasksWithZombie.map((t) => t.assignee).filter(Boolean))];

			return {
				...formatModuleResponse(mod),
				tasks: tasksWithZombie,
				totalTasks,
				doneTasks,
				progressPercent,
				assignees
			};
		})
	);

	return {
		...formatMilestoneResponse(milestone),
		modules: modulesWithTasks
	};
}

// ── Formatters ───────────────────────────────────────────────────────────────

function formatMilestoneResponse(row: any) {
	return {
		id: row.id,
		title: row.title,
		sourceMd: row.sourceMd,
		gitUrl: row.gitUrl,
		status: row.status,
		createdAt: new Date(row.createdAt).toISOString()
	};
}

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatTaskResponse(row: any) {
	let evidence: Array<{ command: string; exitCode: number; verdict: string }> | null = null;
	if (row.evidenceJson) {
		try { evidence = JSON.parse(row.evidenceJson); } catch { evidence = null; }
	}
	let filesTouched: string[] | null = null;
	if (row.filesTouched) {
		try { filesTouched = JSON.parse(row.filesTouched); } catch { filesTouched = null; }
	}
	return {
		id: row.id,
		shortId: row.shortId,
		moduleId: row.moduleId,
		title: row.title,
		description: row.description,
		references: row.references,
		status: row.status,
		assignee: row.assignee,
		subTotal: row.subTotal,
		subDone: row.subDone,
		progressMessage: row.progressMessage,
		blockedReason: row.blockedReason ?? null,
		commitHash: row.commitHash,
		evidence,
		filesTouched,
		createdAt: new Date(row.createdAt).toISOString(),
		updatedAt: new Date(row.updatedAt).toISOString(),
		reportedAt: row.reportedAt ? new Date(row.reportedAt).toISOString() : null
	};
}

import { z } from 'zod';
import { taskStatusEnum } from '../db/schema.js';
import { taskIdSchema, moduleIdSchema } from './common.js';

// ── Status transition map ───────────────────────────────────────────────────

const validTransitions: Record<string, string[]> = {
	todo: ['in-progress', 'skipped'],
	'in-progress': ['blocked', 'review', 'todo'],
	blocked: ['in-progress', 'todo'],
	review: ['done', 'in-progress'],
	done: [],
	skipped: []
};

export function isValidTransition(from: string, to: string): boolean {
	return validTransitions[from]?.includes(to) ?? false;
}

// ── Claim ───────────────────────────────────────────────────────────────────

export const claimTaskSchema = z.object({
	assignee: z.string().min(1, 'Assignee is required').max(100)
});
export type ClaimTaskInput = z.infer<typeof claimTaskSchema>;

// ── Progress update ─────────────────────────────────────────────────────────

export const progressTaskSchema = z.object({
	progressMessage: z.string().max(5000).optional(),
	subTotal: z.number().int().nonnegative().optional(),
	subDone: z.number().int().nonnegative().optional()
}).refine(
	(data) => {
		if (data.subTotal !== undefined && data.subDone !== undefined) {
			return data.subDone <= data.subTotal;
		}
		return true;
	},
	{ message: 'sub_done cannot exceed sub_total', path: ['subDone'] }
);
export type ProgressTaskInput = z.infer<typeof progressTaskSchema>;

// ── Complete ────────────────────────────────────────────────────────────────

const evidenceItemSchema = z.object({
	command: z.string().max(500),
	exitCode: z.number().int(),
	verdict: z.enum(['pass', 'fail', 'skip', 'error'])
});

export const completeTaskSchema = z.object({
	commitHash: z.string().max(40).optional(),
	progressMessage: z.string().max(5000).optional(),
	evidence: z.array(evidenceItemSchema).max(50).optional(),
	filesTouched: z.array(z.string().max(500)).max(200).optional()
});
export type CompleteTaskInput = z.infer<typeof completeTaskSchema>;

// ── Admin action ────────────────────────────────────────────────────────────

export const adminTaskActionSchema = z.object({
	status: z.enum(taskStatusEnum),
	progressMessage: z.string().max(5000).optional(),
	assignee: z.string().max(100).nullable().optional()
});
export type AdminTaskActionInput = z.infer<typeof adminTaskActionSchema>;

// ── Update task (edit properties) ───────────────────────────────────────────

export const updateTaskSchema = z.object({
	title: z.string().min(1).max(300).optional(),
	description: z.string().max(10000).nullable().optional(),
	assignee: z.string().max(100).nullable().optional()
});
export type UpdateTaskInput = z.infer<typeof updateTaskSchema>;

// ── Block ────────────────────────────────────────────────────────────────────

export const blockTaskSchema = z.object({
	reason: z.string().min(1, 'Block reason is required').max(2000)
});
export type BlockTaskInput = z.infer<typeof blockTaskSchema>;

// ── Unblock ──────────────────────────────────────────────────────────────────

export const unblockTaskSchema = z.object({
	message: z.string().max(5000).optional()
});
export type UnblockTaskInput = z.infer<typeof unblockTaskSchema>;

// ── Response (with resolved references) ─────────────────────────────────────

export const taskResponseSchema = z.object({
	id: taskIdSchema,
	shortId: z.number().int().positive(),
	moduleId: moduleIdSchema,
	title: z.string(),
	description: z.string().nullable(),
	references: z.string().nullable(),
	status: z.enum(taskStatusEnum),
	assignee: z.string().nullable(),
	subTotal: z.number().int().nonnegative(),
	subDone: z.number().int().nonnegative(),
	progressMessage: z.string().nullable(),
	blockedReason: z.string().nullable(),
	commitHash: z.string().nullable(),
	evidence: z.array(z.object({
		command: z.string(),
		exitCode: z.number().int(),
		verdict: z.string()
	})).nullable(),
	filesTouched: z.array(z.string()).nullable(),
	createdAt: z.string().datetime(),
	updatedAt: z.string().datetime(),
	reportedAt: z.string().datetime().nullable()
});
export type TaskResponse = z.infer<typeof taskResponseSchema>;

import { sqliteTable, text, integer, index } from 'drizzle-orm/sqlite-core';
import { sql } from 'drizzle-orm';

// ── Status enums (stored as text in SQLite, validated by Zod at app layer) ──

export const milestoneStatusEnum = ['draft', 'in-progress', 'completed', 'archived'] as const;
export type MilestoneStatus = (typeof milestoneStatusEnum)[number];

export const moduleStatusEnum = ['draft', 'in-progress', 'completed'] as const;
export type ModuleStatus = (typeof moduleStatusEnum)[number];

export const taskStatusEnum = [
	'todo',
	'in-progress',
	'blocked',
	'review',
	'done',
	'skipped'
] as const;
export type TaskStatus = (typeof taskStatusEnum)[number];

// ── Milestone ────────────────────────────────────────────────────────────────
// Primary entity. ID format: MS-{seq} (e.g. MS-1, MS-2).

export const milestones = sqliteTable(
	'milestones',
	{
		id: text('id').primaryKey(), // MS-{seq}
		title: text('title').notNull(),
		sourceMd: text('source_md'),
		gitUrl: text('git_url'),
		status: text('status', { enum: milestoneStatusEnum }).notNull().default('draft'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`)
	},
	(table) => [index('milestone_status_idx').on(table.status)]
);

// ── Module ───────────────────────────────────────────────────────────────────
// Groups tasks within a milestone. ID format: MOD-{milestone_seq}-{seq}.

export const modules = sqliteTable(
	'modules',
	{
		id: text('id').primaryKey(), // MOD-{ms_seq}-{seq}
		milestoneId: text('milestone_id')
			.notNull()
			.references(() => milestones.id, { onDelete: 'cascade' }),
		name: text('name').notNull(),
		description: text('description'),
		status: text('status', { enum: moduleStatusEnum }).notNull().default('draft'),
		sortOrder: integer('sort_order').notNull().default(0)
	},
	(table) => [
		index('module_milestone_id_idx').on(table.milestoneId),
		index('module_status_idx').on(table.status)
	]
);

// ── Task ─────────────────────────────────────────────────────────────────────
// Atomic unit of work. ID format: TASK-{global_seq}.
// short_id is a global auto-increment for human-friendly references.

export const tasks = sqliteTable(
	'tasks',
	{
		id: text('id').primaryKey(), // TASK-{global_seq}
		shortId: integer('short_id').notNull().unique(), // global auto-increment
		moduleId: text('module_id')
			.notNull()
			.references(() => modules.id, { onDelete: 'cascade' }),
		title: text('title').notNull(),
		description: text('description'),
		references: text('references'), // JSON or text blob
		status: text('status', { enum: taskStatusEnum }).notNull().default('todo'),
		assignee: text('assignee'),
		subTotal: integer('sub_total').notNull().default(0),
		subDone: integer('sub_done').notNull().default(0),
		progressMessage: text('progress_message'),
		blockedReason: text('blocked_reason'),
		commitHash: text('commit_hash'),
		evidenceJson: text('evidence_json'),
		filesTouched: text('files_touched'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		updatedAt: integer('updated_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		reportedAt: integer('reported_at', { mode: 'timestamp' })
	},
	(table) => [
		index('task_status_module_idx').on(table.status, table.moduleId),
		index('task_status_reported_idx').on(table.status, table.reportedAt),
		index('task_module_id_idx').on(table.moduleId),
		index('task_short_id_idx').on(table.shortId)
	]
);

// ── Type exports for use in application code ──

export type Milestone = typeof milestones.$inferSelect;
export type NewMilestone = typeof milestones.$inferInsert;
export type Module = typeof modules.$inferSelect;
export type NewModule = typeof modules.$inferInsert;
export type Task = typeof tasks.$inferSelect;
export type NewTask = typeof tasks.$inferInsert;

import { eq, desc } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { milestones, modules, tasks } from '$lib/db/schema.js';
import type { CreateMilestoneInput, UpdateMilestoneInput } from '$lib/schemas/index.js';

// ── ID Generation ────────────────────────────────────────────────────────────

/** Get next MS-{seq} ID by querying max existing seq. */
export async function nextMilestoneId(db: BetterSQLite3Database<any>): Promise<string> {
	const rows = await db.select({ id: milestones.id }).from(milestones).all();
	let maxSeq = 0;
	for (const row of rows) {
		const seq = parseInt(row.id.replace('MS-', ''), 10);
		if (seq > maxSeq) maxSeq = seq;
	}
	return `MS-${maxSeq + 1}`;
}

// ── Create ───────────────────────────────────────────────────────────────────

export async function createMilestone(
	db: BetterSQLite3Database<any>,
	data: CreateMilestoneInput
) {
	const id = await nextMilestoneId(db);
	const result = await db
		.insert(milestones)
		.values({
			id,
			title: data.title,
			sourceMd: data.sourceMd ?? null,
			gitUrl: data.gitUrl && data.gitUrl !== '' ? data.gitUrl : null
		})
		.returning()
		.get();
	return formatMilestoneResponse(result);
}

// ── List ─────────────────────────────────────────────────────────────────────

export async function listMilestones(db: BetterSQLite3Database<any>) {
	const rows = await db.select().from(milestones).orderBy(desc(milestones.createdAt), desc(milestones.id)).all();
	return rows.map(formatMilestoneResponse);
}

// ── Get Detail ───────────────────────────────────────────────────────────────

export async function getMilestone(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const milestone = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, id))
		.get();

	if (!milestone) return null;

	// Fetch modules for this milestone
	const modRows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, id))
		.all();

	// Fetch tasks for each module
	const modulesWithTasks = await Promise.all(
		modRows.map(async (mod) => {
			const taskRows = await db
				.select()
				.from(tasks)
				.where(eq(tasks.moduleId, mod.id))
				.all();
			return {
				...formatModuleResponse(mod),
				tasks: taskRows.map(formatTaskResponse)
			};
		})
	);

	return {
		...formatMilestoneResponse(milestone),
		modules: modulesWithTasks
	};
}

// ── Update ───────────────────────────────────────────────────────────────────

export async function updateMilestone(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateMilestoneInput
) {
	const existing = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, id))
		.get();

	if (!existing) return null;

	const updates: Record<string, any> = {};
	if (data.title !== undefined) updates.title = data.title;
	if (data.sourceMd !== undefined) updates.sourceMd = data.sourceMd ?? null;
	if (data.gitUrl !== undefined) updates.gitUrl = data.gitUrl === '' ? null : data.gitUrl;
	if (data.status !== undefined) updates.status = data.status;

	if (Object.keys(updates).length === 0) {
		return formatMilestoneResponse(existing);
	}

	const result = await db
		.update(milestones)
		.set(updates)
		.where(eq(milestones.id, id))
		.returning()
		.get();

	return formatMilestoneResponse(result);
}

// ── Formatters ───────────────────────────────────────────────────────────────

function formatMilestoneResponse(row: any) {
	return {
		id: row.id,
		title: row.title,
		sourceMd: row.sourceMd,
		gitUrl: row.gitUrl,
		status: row.status,
		createdAt: new Date(row.createdAt).toISOString()
	};
}

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

function formatTaskResponse(row: any) {
	return {
		id: row.id,
		shortId: row.shortId,
		moduleId: row.moduleId,
		title: row.title,
		description: row.description,
		references: row.references,
		status: row.status,
		assignee: row.assignee,
		subTotal: row.subTotal,
		subDone: row.subDone,
		progressMessage: row.progressMessage,
		commitHash: row.commitHash,
		createdAt: new Date(row.createdAt).toISOString(),
		updatedAt: new Date(row.updatedAt).toISOString(),
		reportedAt: row.reportedAt ? new Date(row.reportedAt).toISOString() : null
	};
}

export { formatModuleResponse, formatTaskResponse };

